themes.template:
---
isbn: {{ metaData.isbn }}
lastReadDate: {{ metaData.lastReadDate }}
---
# 元数据
> [!abstract] {{ metaData.title }}
> - ![ {{ metaData.title }}|200]({{ metaData.cover }})
> - 书名： {{ metaData.title }}
> - 作者： {{ metaData.author }}
> - 简介： {% set intro = metaData.intro | replace("\n","") | replace("\r","") %}{{ intro }}
> - 出版时间： {{ metaData.publishTime }}
> - ISBN： {{ metaData.isbn }}
> - 分类： {{ metaData.category }}
> - 出版社： {{ metaData.publisher }}
> - PC地址：{{ metaData.pcUrl }}

# 高亮划线
{% if syncPopularHighlightsToggle %}
{% for chapter in chapterHighlights %}
{% if chapter.level == 1 %}
## {{ chapter.chapterTitle }}
{% elif chapter.level == 2 %}
### {{ chapter.chapterTitle }}
{% elif chapter.level == 3 %}
#### {{ chapter.chapterTitle }}
{% endif %}
{% for highlight in chapter.highlights %}
{% set rangeParts = highlight.range | split("-") %}
{% set deeplink = "weread://bestbookmark?bookId=" + metaData.bookId + "&chapterUid=" + highlight.chapterUid + "&rangeStart=" + rangeParts[0] + "&rangeEnd=" + rangeParts[1] %}
{% if highlight.isPopular and highlight.isUserHighlight %}
{# 用户自己的划线 + 热门：📌🔥 + 共读人数 #}
{% if highlight.reviewContent %}
> 📌🔥 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> 🔥 {{ highlight.popularCount }} 人共读
> 💭 {{ highlight.reviewContent }} 
> ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}
{% else %}
> 📌🔥 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> 🔥 {{ highlight.popularCount }} 人共读
> ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}

{% endif %}
{% elif highlight.isPopular %}
{# 只有热门划线（非用户）：🔥 + 共读人数 #}
> 🔥 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> 📊 {{ highlight.popularCount }} 人共读 ^{{ highlight.bookmarkId }}

{% else %}
{# 普通用户划线（非热门）：📌 #}
{% if highlight.reviewContent %}
> 📌 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> 💭 {{ highlight.reviewContent }} 
> ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}
{% else %}
> 📌 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}

{% endif %}
{% endif %}
{% endfor %}
{% endfor %}
{% else %}
{% for chapter in chapterHighlights %}
{% if chapter.level == 1 %}
## {{ chapter.chapterTitle }}
{% elif chapter.level == 2 %}
### {{ chapter.chapterTitle }}
{% elif chapter.level == 3 %}
#### {{ chapter.chapterTitle }}
{% endif %}
{% for highlight in chapter.highlights %}
{% set rangeParts = highlight.range | split("-") %}
{% set deeplink = "weread://bestbookmark?bookId=" + metaData.bookId + "&chapterUid=" + highlight.chapterUid + "&rangeStart=" + rangeParts[0] + "&rangeEnd=" + rangeParts[1] %}
{# 普通用户划线（不显示热门）：📌 #}
{% if highlight.reviewContent %}
> 📌 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
 💭 {{ highlight.reviewContent }} 
 ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}
{% else %}
> 📌 [{{ highlight.markText | trim }}](<{{ deeplink }}>)
> ⏱ {{ highlight.createTime }} ^{{ highlight.bookmarkId }}

{% endif %}
{% endfor %}
{% endfor %}
{% endif %}

# 读书笔记
{% for chapter in bookReview.chapterReviews %}
{% if chapter.reviews or chapter.chapterReview %}
## {{ chapter.chapterTitle }}
{% if chapter.chapterReviews %}
{% for chapterReview in chapter.chapterReviews %}
### 章节评论 No.{{ loop.index }}
- {{ chapterReview.content }} ^{{ chapterReview.reviewId }}
    - ⏱ {{ chapterReview.createTime }}
{% endfor %}
{% endif %}
{% if chapter.reviews %}
{% for review in chapter.reviews %}
### 划线评论
> 📌 {{ review.abstract | trim }} ^{{ review.reviewId }}
    💭 {{ review.content }}
    ⏱ {{ review.createTime }}
{% endfor %}
{% endif %}
{% endif %}
{% endfor %}

# 本书评论
{% if bookReview.bookReviews %}
{% for bookReview in bookReview.bookReviews %}
## 书评 No.{{ loop.index }}
{{ bookReview.mdContent }} ^{{ bookReview.reviewId }}
⏱ {{ bookReview.createTime }}
{% endfor %}
{% endif %}

